1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  material?: string;
14	  enchantment?: number;
15	  cursed?: boolean;
16	};
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Step = QuoteStep;
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	
21	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
22	
23	const FIRST_INSURANCE_RATE = 0.1;
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const BLOCK_SIZE = 3;
27	const BLOCK_BASE_PREMIUM = 60;
28	
29	const countByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
33	  }
34	  return counts;
35	};
36	
37	const groupBase = (type: string, count: number): number =>
38	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
39	    ? BLOCK_BASE_PREMIUM
40	    : count * basePremiumFor(type);
41	
42	const policyBase = (items: Item[]): number => {
43	  let total = 0;
44	  for (const [type, count] of countByType(items)) {
45	    total += groupBase(type, count);
46	  }
47	  return total;
48	};
49	
50	const firstInsuranceSurcharge = (base: number): number =>
51	  base * FIRST_INSURANCE_RATE;
52	
53	const CURSE_RATE = 0.5;
54	
55	const curseSurcharge = (item: Item): number =>
56	  item.cursed ? basePremiumFor(item.type) * CURSE_RATE : 0;
57	
58	const itemSurcharges = (items: Item[]): number =>
59	  items.reduce((sum, item) => sum + curseSurcharge(item), 0);
60	
61	const quotePremium = (items: Item[]): number => {
62	  const base = policyBase(items);
63	  const surcharges = itemSurcharges(items);
64	  return Math.ceil(
65	    base + surcharges + firstInsuranceSurcharge(base) + PROCESSING_FEE,
66	  );
67	};
68	
69	export const processScenario = (scenario: Scenario): unknown => {
70	  const results = scenario.steps.map((step) => ({
71	    premium: quotePremium(step.items),
72	  }));
73	  return { results };
74	};
